code.perFrame:
zoom = 1.0095;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
//Unchained's Beat Code;
old_bass_flop=bass_flop;;
old_treb_flop=treb_flop;;
old_mid_flop=mid_flop;;
chaos=.9+.1*sin(pulse);;
entropy=if(((pulse) == (-20)),1+bass_flop+treb_flop+mid_flop+rand(2),entropy);;
bass_thresh = ((bass_att) > (bass_thresh))*2 + (1-((bass_att) > (bass_thresh)))*((bass_thresh-1.3)*chaos+1.3);;
bass_flop=abs(bass_flop-((bass_thresh) == (2)));;
treb_thresh=((treb_att) > (treb_thresh))*2 + (1-((treb_att) > (treb_thresh)))*((treb_thresh-1.3)*chaos+1.3);;
treb_flop=abs(treb_flop-((treb_thresh) == (2)));;
mid_thresh=((mid_att) > (mid_thresh))*2 + (1-((mid_att) > (mid_thresh)))*((mid_thresh-1.3)*chaos+1.3);;
mid_flop=abs(mid_flop-((mid_thresh) == (2)));;
bass_changed=bnot(((old_bass_flop) == (bass_flop)));;
mid_changed=bnot(((old_mid_flop) == (mid_flop)));;
treb_changed=bnot(((old_treb_flop) == (treb_flop)));;
bass_residual = bass_changed*sin(pulse*.1*entropy) + bnot(bass_changed)*bass_residual;;
treb_residual = treb_changed*sin(pulse*.1*entropy) + bnot(treb_changed)*treb_residual;;
mid_residual = mid_changed*sin(pulse*.1*entropy) + bnot(mid_changed)*mid_residual;;
pulse=if(((abs(pulse)) > (20)),-20,pulse+(bass_thresh+mid_thresh+treb_thresh)*.032);;
q1=mid_residual;;
q2=bass_residual;;
q3=treb_residual;;
q4=sin(pulse);;
q5=cos(pulse/2+q1);;
q6=sin(q3*q1+q7*q2);;
q7=((q1) > (0))+((q2) > (0))+((q3) > (0))+((q3) > (0))*treb_flop+((q2) > (0))*bass_flop+((q1) > (0))*mid_flop;;
q8=entropy;;
vol=(bass+mid+treb_att)*.3333;;
redsine=.5+.15*bass*sin(time*3);;
greensine=.5+.15*mid*sin(time*2);;
bluesine=.5+.15*treb*sin(time);;
redif=if(((bass) > (1.2)),redsine,if(((redif) > (.95)),.0,redif*.95));;
greenif=if(((mid) > (1.2)),greensine,if(((greenif) > (.95)),.0,greenif*.95));;
blueif=if(((treb) > (1.2)),bluesine,if(((blueif) > (.95)),.0,blueif*.95));;
r=redif;;
g=greenif;;
b=blueif;;
q9=r;;
q10=g;;
q11=b;;
wave_r=wave_r*(sin(redif*cos(b+g)));;
wave_g=wave_g*(sin(greenif*cos(r+b)));;
wave_b=wave_b*(sin(blueif*cos(r+g)));;
ib_r=r;;
ib_g=g;;
ib_b=b;;
ob_r=wave_r*redif;;
ob_g=wave_g*greenif;;
ob_b=wave_b*blueif;

